# Lazy initialization for compiled regexes
once_cell = "1.19"

[features]
default = []

# Enable rich_rust styled output
rich = ["dep:rich_rust"]

# Full feature set
full = ["rich"]

# Legacy colored output (uses colored crate, no rich_rust)
legacy-colors = []
```

## Conditional Compilation
```rust
// In src/output/mod.rs
#[cfg(feature = "rich")]
use rich_rust::prelude::*;

#[cfg(not(feature = "rich"))]
mod fallback {
    // Minimal fallback implementations when rich_rust is not enabled
}

// Feature detection at runtime
pub fn is_rich_available() -> bool {
    cfg!(feature = "rich")
}
```

## Build Configurations
1. **Default** (`cargo build`): Uses colored crate, no rich_rust
2. **Rich** (`cargo build --features rich`): Uses rich_rust for styled output
3. **Full** (`cargo build --features full`): All features enabled
4. **Legacy** (`cargo build --features legacy-colors`): Uses colored crate explicitly

