### Paginated Results Renderer
```rust
pub struct SearchResultsRenderer {
    results: Vec<SearchResult>,
    query: String,
    timing: Duration,
    page_size: usize,
    current_page: usize,
}

impl SearchResultsRenderer {
    pub fn new(results: Vec<SearchResult>, query: &str, timing: Duration) -> Self {
        Self {
            results,
            query: query.to_string(),
            timing,
            page_size: 10,
            current_page: 0,
        }
    }

    pub fn page_size(mut self, size: usize) -> Self {
        self.page_size = size.max(1);
        self
    }

    pub fn total_pages(&self) -> usize {
        (self.results.len() + self.page_size - 1) / self.page_size
    }

    pub fn render(&self, output: &Output) {
        let terms = extract_terms(&self.query);

        // Header
        if output.is_styled() {
            let header = format!(
                "[{}]Found {} results for \"{}\" in {:.2}ms[/]",
                output.theme.heading,
                self.results.len(),
                self.query,
                self.timing.as_secs_f64() * 1000.0
            );
            output.print(&header);
        } else {
            println!(
                "Found {} results for \"{}\" in {:.2}ms",
                self.results.len(),
                self.query,
                self.timing.as_secs_f64() * 1000.0
            );
        }

        if self.results.is_empty() {
            return;
        }

        // Calculate page bounds
        let start = self.current_page * self.page_size;
        let end = (start + self.page_size).min(self.results.len());

        // Render results for current page
        for result in &self.results[start..end] {
            let card = SearchResultCard::new()
                .doc_id(&result.doc_id)
                .doc_type(&result.doc_type)
                .content(&result.content)
                .score(result.score)
                .timestamp(result.timestamp)
                .highlight_terms(terms.clone());

            card.render(output);
        }

        // Page indicator
        if self.total_pages() > 1 {
            if output.is_styled() {
                output.print(&format!(
                    "[{}]Page {} of {}[/]",
                    output.theme.muted,
                    self.current_page + 1,
                    self.total_pages()
                ));
            } else {
                println!("Page {} of {}", self.current_page + 1, self.total_pages());
            }
        }
    }
}

/// Convenience function for rendering search results
pub fn render_search_results(
    output: &Output,
    results: &[SearchResult],
    query: &str,
    timing: Duration,
) {
    SearchResultsRenderer::new(results.to_vec(), query, timing).render(output);
}
