### Color Support Detection
```rust
use std::env;

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum ColorSupport {
    None,       // No color support
    Basic,      // 16 colors (4-bit)
    Extended,   // 256 colors (8-bit)
    TrueColor,  // 16M colors (24-bit)
}

impl ColorSupport {
    pub fn detect() -> Self {
        // NO_COLOR always wins
        if env::var("NO_COLOR").is_ok() {
            return Self::None;
        }

        // COLORTERM=truecolor is definitive
        if let Ok(ct) = env::var("COLORTERM") {
            if ct == "truecolor" || ct == "24bit" {
                return Self::TrueColor;
            }
        }

        // Check TERM for color hints
        if let Ok(term) = env::var("TERM") {
            if term.contains("256color") || term.contains("256-color") {
                return Self::Extended;
            }
            if term.contains("color") || term == "xterm" || term == "screen" {
                return Self::Basic;
            }
            if term == "dumb" {
                return Self::None;
            }
        }

        // Default to basic colors if we have a TTY
        Self::Basic
    }
}
```

